const input = $json ?? {};

const rawStatus = String(input.status ?? 'unknown').trim().toLowerCase();
const status = rawStatus === 'success' ? 'success' : rawStatus === 'failed' ? 'failed' : rawStatus === 'info' ? 'info' : 'unknown';
const sourceWorkflow = String(input.source_workflow ?? 'Unnamed Workflow').trim() || 'Unnamed Workflow';
const summary = String(input.summary ?? '').trim();
const details = String(input.details ?? '').trim();
const title = 'n8n ' + status.toUpperCase() + ': ' + sourceWorkflow;
const body = [summary, details].filter((value) => value.length > 0).join(' | ') || 'Workflow execution finished.';
const compactBody = body.replace(/\s+/g, ' ').trim().slice(0, 1000);

const hasExplicitTargets = Object.prototype.hasOwnProperty.call(input, 'notify_targets') && input.notify_targets !== null;
const rawTargets = hasExplicitTargets ? input.notify_targets : 'telegram';

let targets = Array.isArray(rawTargets)
  ? rawTargets
  : String(rawTargets).split(/[\s,]+/);

targets = targets
  .map((value) => String(value).trim().toLowerCase())
  .filter((value) => value.length > 0)
  .map((value) => {
    if (value === 'googlechat' || value === 'google_chat' || value === 'gg-chat') {
      return 'ggchat';
    }
    return value;
  });

if (targets.includes('all')) {
  targets = ['telegram', 'ggchat'];
}

if (targets.includes('none') || targets.includes('off') || targets.includes('disable')) {
  targets = [];
}

targets = [...new Set(targets.filter((value) => ['telegram', 'ggchat'].includes(value)))];
if (targets.length === 0 && !hasExplicitTargets) {
  targets = ['telegram'];
}

const telegramBotToken = String(input.telegram_bot_token ?? '').trim();
const telegramChatId = String(input.telegram_chat_id ?? '').trim();
const ggchatWebhookUrl = String(input.ggchat_webhook_url ?? '').trim();

return [{
  json: {
    status,
    source_workflow: sourceWorkflow,
    summary,
    details,
    title,
    body: compactBody,
    notify_targets: targets,
    telegram_enabled: targets.includes('telegram'),
    ggchat_enabled: targets.includes('ggchat'),
    telegram_bot_token: telegramBotToken,
    telegram_chat_id: telegramChatId,
    ggchat_webhook_url: ggchatWebhookUrl
  }
}];

if ($json.telegram_enabled !== true) {
  return [];
}

const botToken = String($json.telegram_bot_token ?? '').trim();
const chatId = String($json.telegram_chat_id ?? '').trim();
if (!botToken || !chatId) {
  return [];
}

const text = [String($json.title ?? ''), String($json.body ?? '')]
  .filter((value) => value.trim() !== '')
  .join('\n')
  .slice(0, 3500);

return [{
  json: {
    telegram_url: `https://api.telegram.org/bot${botToken}/sendMessage`,
    telegram_body: {
      chat_id: chatId,
      text,
      disable_web_page_preview: true
    }
  }
}];

if ($json.ggchat_enabled !== true) {
  return [];
}

const webhookUrl = String($json.ggchat_webhook_url ?? '').trim();
if (!webhookUrl) {
  return [];
}

const text = [String($json.title ?? ''), String($json.body ?? '')]
  .filter((value) => value.trim() !== '')
  .join('\n')
  .slice(0, 3500);

return [{
  json: {
    ggchat_webhook_url: webhookUrl,
    ggchat_body: {
      text
    }
  }
}];
